const canvas = document.getElementById('molecule-canvas');
const ctx = canvas.getContext('2d');
let atoms = [];
let animReq;

const rs = () => { 
    canvas.width = canvas.clientWidth * window.devicePixelRatio; 
    canvas.height = canvas.clientHeight * window.devicePixelRatio; 
    ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
};
window.addEventListener('resize', rs); rs();

const enableBtn = (id) => { const b = document.getElementById(id); b.disabled = false; b.style.opacity = '1'; };

window.runStep1 = () => {
    document.getElementById('btn-1').innerText = "GENERATING_LIGANDS...";
    const w = canvas.width/window.devicePixelRatio;
    const h = canvas.height/window.devicePixelRatio;

    // Create "Molecules" (Clusters of Atoms)
    atoms = [];
    for(let m=0; m<5; m++) {
        const mx = Math.random() * w;
        const my = Math.random() * h;
        const count = 10 + Math.random() * 20;
        for(let i=0; i<count; i++) {
            atoms.push({
                x: mx + (Math.random()-0.5)*100,
                y: my + (Math.random()-0.5)*100,
                type: ['C', 'O', 'N'][Math.floor(Math.random()*3)],
                vx: (Math.random()-0.5)*2,
                vy: (Math.random()-0.5)*2,
                id: atoms.length
            });
        }
    }

    document.getElementById('btn-1').innerText = "LIGANDS_IN_BUFFER";
    enableBtn('btn-2');
    render();
};

const render = () => {
    ctx.fillStyle = '#000';
    ctx.fillRect(0,0,canvas.width,canvas.height);

    // Draw Connections (Edges)
    ctx.strokeStyle = 'rgba(0, 255, 157, 0.2)';
    ctx.lineWidth = 1;
    for(let i=0; i<atoms.length; i++) {
        for(let j=i+1; j<atoms.length; j++) {
            const dx = atoms[i].x - atoms[j].x;
            const dy = atoms[i].y - atoms[j].y;
            const dist = Math.sqrt(dx*dx + dy*dy);
            if(dist < 50) {
                ctx.beginPath(); ctx.moveTo(atoms[i].x, atoms[i].y); ctx.lineTo(atoms[j].x, atoms[j].y); ctx.stroke();
            }
        }
    }

    // Draw Atoms
    atoms.forEach(a => {
        ctx.fillStyle = a.type === 'C' ? '#aaa' : (a.type === 'O' ? '#ff4444' : '#4444ff');
        ctx.shadowBlur = 10; ctx.shadowColor = ctx.fillStyle;
        ctx.beginPath(); ctx.arc(a.x, a.y, 4, 0, 7); ctx.fill();
        ctx.shadowBlur = 0;
    });
};

window.runStep2 = () => {
    document.getElementById('btn-2').innerText = "SUBGROUP_SYNC_ACTIVE";
    enableBtn('btn-3');
    // Visualizing the SIMD spatial scan
    const loop = () => {
        atoms.forEach(a => {
            a.x += a.vx; a.y += a.vy;
            if(a.x < 0 || a.x > canvas.width/devicePixelRatio) a.vx *= -1;
            if(a.y < 0 || a.y > canvas.height/devicePixelRatio) a.vy *= -1;
        });
        render();
        animReq = requestAnimationFrame(loop);
    };
    loop();
};

window.runStep3 = () => {
    document.getElementById('btn-3').innerText = "DOCKING_COMPUTED";
    // Predict Binding Affinity based on cluster density
    let score = 0;
    atoms.forEach(a => {
        let density = atoms.filter(other => Math.sqrt((a.x-other.x)**2 + (a.y-other.y)**2) < 40).length;
        score += density;
    });

    const finalAffinity = -(score / atoms.length * 2.5).toFixed(2);
    document.getElementById('affinity-val').innerText = finalAffinity + " kcal/mol";
    document.getElementById('affinity-val').style.color = finalAffinity < -8 ? '#00ff9d' : '#ffcc00';

    window.axiomaticLog({ event: 'Docking_Complete', affinity: finalAffinity });
};
